  fontSize: 12,
  fontWeight: "bold",
  color: "#888",
  textTransform: "uppercase",
  letterSpacing: 1,
  marginBottom: 8,
  marginTop: 0,
};

const BADGE = (color: string): React.CSSProperties => ({
  display: "inline-block",
  padding: "1px 6px",
  borderRadius: 3,
  background: color,
  color: "#fff",
  fontSize: 11,
  marginLeft: 6,
});

function levelBadge(level: number): string {
  return level === 0 ? "#555" : level === 1 ? "#39e" : level === 2 ? "#3ce" 
    : level === 3 ? "#3ae" : level === 4 ? "#2a8" : "#1a7";
}

function riskColor(score: number): string {
  return score > 0.7 ? "#e53" : score > 0.4 ? "#e93" : "#1a7";
}

export default function AgentProfiles() {
  const [agents, setAgents] = useState<AgentProfile[]>([]);
  const [selected, setSelected] = useState<AgentProfile | null>(null);

  useEffect(() => {
    async function load() {
      try {
        const data = await getAgents();
        setAgents(data);
        if (data.length > 0) setSelected(data[0]);
      } catch {
        setAgents([]);
      }
    }
    load();
    const t = setInterval(load, 10000);
    return () => clearInterval(t);
  }, []);

